import React, { useState, useEffect } from 'react';
import { paiementService } from '../../services/api';
import { useToast } from '../../components/UI';

const PaiementsPage = () => {
  const [abonnes, setAbonnes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth() + 1);
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [updating, setUpdating] = useState(null);
  const { show } = useToast();

  const months = [
    'Janvier', 'Février', 'Mars', 'Avril', 'Mai', 'Juin',
    'Juillet', 'Août', 'Septembre', 'Octobre', 'Novembre', 'Décembre'
  ];

  const statusColors = {
    paye: 'bg-green-100 text-green-800',
    impaye: 'bg-red-100 text-red-800',
    en_attente: 'bg-yellow-100 text-yellow-800'
  };

  const statusLabels = {
    paye: 'Payé',
    impaye: 'Impayé',
    en_attente: 'En attente'
  };

  useEffect(() => {
    loadPaiements();
  }, [selectedMonth, selectedYear]);

  const loadPaiements = async () => {
    try {
      setLoading(true);
      const response = await paiementService.gestion({
        mois: selectedMonth,
        annee: selectedYear
      });
      setAbonnes(response.data);
    } catch (error) {
      toast.error('Erreur lors du chargement des paiements');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusChange = async (userId, newStatus) => {
    try {
      setUpdating(userId);
      await paiementService.marquerMensuel({
        user_id: userId,
        mois: selectedMonth,
        annee: selectedYear,
        statut: newStatus
      });

      toast.success(`Paiement marqué comme ${statusLabels[newStatus]}`);
      loadPaiements(); // Recharger les données
    } catch (error) {
      toast.error('Erreur lors de la mise à jour du paiement');
      console.error(error);
    } finally {
      setUpdating(null);
    }
  };

  const getStatusBadge = (statut) => {
    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${statusColors[statut] || 'bg-gray-100 text-gray-800'}`}>
        {statusLabels[statut] || statut}
      </span>
    );
  };

  return (
    <div className="p-6">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900 mb-4">
          Gestion des Paiements Mensuels
        </h1>

        {/* Filtres mois/année */}
        <div className="flex gap-4 mb-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Mois
            </label>
            <select
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              className="border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {months.map((month, index) => (
                <option key={index + 1} value={index + 1}>
                  {month}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Année
            </label>
            <select
              value={selectedYear}
              onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              className="border border-gray-300 rounded-md px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              {[2024, 2025, 2026, 2027].map(year => (
                <option key={year} value={year}>
                  {year}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* Statistiques rapides */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          <div className="bg-white p-4 rounded-lg shadow">
            <div className="text-2xl font-bold text-green-600">
              {abonnes.filter(a => a.paiement?.statut === 'paye').length}
            </div>
            <div className="text-sm text-gray-600">Payés</div>
          </div>
          <div className="bg-white p-4 rounded-lg shadow">
            <div className="text-2xl font-bold text-red-600">
              {abonnes.filter(a => a.paiement?.statut === 'impaye').length}
            </div>
            <div className="text-sm text-gray-600">Impayés</div>
          </div>
          <div className="bg-white p-4 rounded-lg shadow">
            <div className="text-2xl font-bold text-yellow-600">
              {abonnes.filter(a => !a.paiement || a.paiement?.statut === 'en_attente').length}
            </div>
            <div className="text-sm text-gray-600">En attente</div>
          </div>
        </div>
      </div>

      {/* Liste des abonnés */}
      <div className="bg-white shadow rounded-lg overflow-hidden">
        {loading ? (
          <div className="p-8 text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto"></div>
            <p className="mt-2 text-gray-600">Chargement...</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Abonné
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Contact
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Statut
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {abonnes.map((abonne) => (
                  <tr key={abonne.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-medium text-gray-900">
                        {abonne.nom_complet}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-gray-900">{abonne.email}</div>
                      <div className="text-sm text-gray-500">{abonne.telephone}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      {getStatusBadge(abonne.paiement?.statut || 'impaye')}
                      {abonne.paiement?.date_paiement && (
                        <div className="text-xs text-gray-500 mt-1">
                          Payé le {new Date(abonne.paiement.date_paiement).toLocaleDateString('fr-FR')}
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex space-x-2">
                        <button
                          onClick={() => handleStatusChange(abonne.id, 'paye')}
                          disabled={updating === abonne.id}
                          className="px-3 py-1 bg-green-600 text-white text-xs rounded hover:bg-green-700 disabled:opacity-50"
                        >
                          {updating === abonne.id ? '...' : 'Marquer Payé'}
                        </button>
                        <button
                          onClick={() => handleStatusChange(abonne.id, 'impaye')}
                          disabled={updating === abonne.id}
                          className="px-3 py-1 bg-red-600 text-white text-xs rounded hover:bg-red-700 disabled:opacity-50"
                        >
                          {updating === abonne.id ? '...' : 'Marquer Impayé'}
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
